export const totalQuestions: number = allQuestions.length;

export function getQuestionsById(ids: string[]): QuizQuestion[] {
  return allQuestions.filter(q => ids.includes(q.id));
}

export function getQuestionsByModule(moduleId: string): QuizQuestion[] {
  return allQuestions.filter(q => q.id.includes(moduleId));
}

